module RefModule(
    input A,
    input B,
    input C,
    input D,
    output Y
);// Define a wire to store the AND of A and B
    wire unused_AB = A & B;

    // Define a wire to store the AND of C and D
    wire CD = C & D;

    // Define a wire to store the AND of unused_AB and CD
    wire ABCD = unused_AB & CD;

    // Assign the output Y to the value of ABCD
    assign Y = ABCD;

endmodule
